import { parseStringPromise } from "xml2js";

// Import bookmarks from a remote XML feed. Uses Node's built-in fetch instead
// of the (deprecated, unmaintained) `request` package.
export async function fetchXml(url) {
  const res = await fetch(url);
  if (res.status >= 400) {
    throw new Error(`upstream ${res.status}`);
  }
  return res.text();
}

